  "inlineSchema": "// backend/prisma/schema.prisma\n\ngenerator client {\n  provider = \"prisma-client-js\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n  url      = env(\"DATABASE_URL\")\n}\n\n// --- ENUMERACIONES ---\n\nenum RoleName {\n  ADMIN\n  GERENTE\n  CLIENTE\n}\n\nenum OrderStatus {\n  PENDING // Pendiente de pago\n  PAID // Pagado\n  SHIPPED // Enviado\n  DELIVERED // Entregado\n  CANCELLED // Cancelado (para tasa de reembolso)\n  REFUNDED // Devuelto (para tasa de reembolso)\n}\n\n// --- MODELOS PRINCIPALES ---\n\nmodel Role {\n  id        String   @id @default(uuid())\n  name      RoleName @unique\n  users     User[]\n  createdAt DateTime @default(now()) @map(\"created_at\")\n\n  @@map(\"roles\")\n}\n\nmodel User {\n  id           String   @id @default(uuid())\n  name         String\n  email        String   @unique\n  passwordHash String   @map(\"password_hash\") // Almacenado con Bcrypt\n  address      String?  @map(\"address\") // el ? significa que puede ser nulo temporalmente\n  roleId       String   @map(\"role_id\")\n  role         Role     @relation(fields: [roleId], references: [id])\n  createdAt    DateTime @default(now()) @map(\"created_at\")\n  updatedAt    DateTime @updatedAt @map(\"updated_at\")\n\n  // Relaciones\n  wishlists Wishlist[]\n  reviews   Review[]\n  carts     Cart[]\n  orders    Order[]\n\n  @@map(\"users\")\n}\n\n// --- CATÁLOGO Y PRODUCTOS ---\n\nmodel Brand {\n  id       String    @id @default(uuid())\n  name     String    @unique // Ej: \"Samsung\", \"Nescafé\"\n  products Product[]\n\n  @@map(\"brands\")\n}\n\nmodel Category {\n  id          String    @id @default(uuid())\n  name        String    @unique // Ej: \"Celulares\", \"Café\"\n  description String?\n  products    Product[]\n\n  @@map(\"categories\")\n}\n\nmodel Product {\n  id          String   @id @default(uuid())\n  name        String\n  description String?\n  price       Decimal  @db.Decimal(10, 2) // Precio de venta al público (S/)\n  cost        Decimal  @db.Decimal(10, 2) // Costo de adquisición (Para gráfica Ingresos vs Costos)\n  stock       Int // Para validar alertas de stock bajo e insuficiente en carrito\n  sku         String   @unique // Visible en las tarjetas del catálogo\n  tags        String[] // Arreglo de strings: [\"Tostado medio\", \"Importado\"]\n  imageUrl    String?  @map(\"image_url\")\n\n  categoryId String   @map(\"category_id\")\n  category   Category @relation(fields: [categoryId], references: [id])\n  brandId    String   @map(\"brand_id\")\n  brand      Brand    @relation(fields: [brandId], references: [id])\n\n  isActive  Boolean  @default(true) @map(\"is_active\")\n  createdAt DateTime @default(now()) @map(\"created_at\")\n  updatedAt DateTime @updatedAt @map(\"updated_at\")\n\n  // Relaciones\n  wishlists  Wishlist[]\n  reviews    Review[]\n  cartItems  CartItem[]\n  orderItems OrderItem[]\n\n  @@map(\"products\")\n}\n\n// --- INTERACCIONES DEL CLIENTE ---\n\nmodel Wishlist {\n  id        String   @id @default(uuid())\n  userId    String   @map(\"user_id\")\n  user      User     @relation(fields: [userId], references: [id], onDelete: Cascade)\n  productId String   @map(\"product_id\")\n  product   Product  @relation(fields: [productId], references: [id], onDelete: Cascade)\n  createdAt DateTime @default(now()) @map(\"created_at\")\n\n  @@unique([userId, productId]) // Un usuario no puede añadir el mismo producto 2 veces a deseos\n  @@map(\"wishlists\")\n}\n\nmodel Review {\n  id        String   @id @default(uuid())\n  userId    String   @map(\"user_id\")\n  user      User     @relation(fields: [userId], references: [id], onDelete: Cascade)\n  productId String   @map(\"product_id\")\n  product   Product  @relation(fields: [productId], references: [id], onDelete: Cascade)\n  rating    Int // 1 a 5 estrellas\n  comment   String?\n  createdAt DateTime @default(now()) @map(\"created_at\")\n\n  @@map(\"reviews\")\n}\n\n// --- CARRITO DE COMPRAS (Para calcular Tasa de Abandono) ---\n\nmodel Cart {\n  id          String   @id @default(uuid())\n  userId      String   @map(\"user_id\")\n  user        User     @relation(fields: [userId], references: [id], onDelete: Cascade)\n  isAbandoned Boolean  @default(false) @map(\"is_abandoned\") // Se marca true si pasa X tiempo sin comprar\n  createdAt   DateTime @default(now()) @map(\"created_at\")\n  updatedAt   DateTime @updatedAt @map(\"updated_at\")\n\n  items CartItem[]\n\n  @@map(\"carts\")\n}\n\nmodel CartItem {\n  id        String  @id @default(uuid())\n  cartId    String  @map(\"cart_id\")\n  cart      Cart    @relation(fields: [cartId], references: [id], onDelete: Cascade)\n  productId String  @map(\"product_id\")\n  product   Product @relation(fields: [productId], references: [id])\n  quantity  Int\n\n  @@map(\"cart_items\")\n}\n\n// --- ÓRDENES Y CHECKOUT ---\n\nmodel Order {\n  id     String @id @default(uuid())\n  userId String @map(\"user_id\")\n  user   User   @relation(fields: [userId], references: [id])\n\n  status        OrderStatus @default(PENDING)\n  paymentMethod String?     @map(\"payment_method\") // Ej: \"Tarjeta de crédito\", \"Yape\", \"Efectivo\"\n\n  // Desglose financiero (Imagen 3)\n  subtotal      Decimal @db.Decimal(10, 2)\n  taxPercentage Decimal @default(18) @map(\"tax_percentage\") @db.Decimal(5, 2) // IGV 18%\n  taxAmount     Decimal @map(\"tax_amount\") @db.Decimal(10, 2)\n  shippingCost  Decimal @default(0) @map(\"shipping_cost\") @db.Decimal(10, 2) // \"Gratis\" = 0\n  totalAmount   Decimal @map(\"total_amount\") @db.Decimal(10, 2)\n\n  createdAt DateTime @default(now()) @map(\"created_at\")\n  updatedAt DateTime @updatedAt @map(\"updated_at\")\n\n  items OrderItem[]\n\n  @@map(\"orders\")\n}\n\nmodel OrderItem {\n  id        String  @id @default(uuid())\n  orderId   String  @map(\"order_id\")\n  order     Order   @relation(fields: [orderId], references: [id], onDelete: Cascade)\n  productId String  @map(\"product_id\")\n  product   Product @relation(fields: [productId], references: [id])\n  quantity  Int\n  unitPrice Decimal @map(\"unit_price\") @db.Decimal(10, 2) // Precio al que se vendió en su momento\n  unitCost  Decimal @map(\"unit_cost\") @db.Decimal(10, 2) // Costo al que se compró en su momento (VITAL para rentabilidad)\n\n  @@map(\"order_items\")\n}\n",
  "inlineSchemaHash": "c9e0818b5f91c7624d6335e8d2f409173cf4bcbc617cf197f45fbefd8adc4de1",
